**Post Hooks (run AFTER the operation)**

```javascript
// Post-save: Log new user creation
userSchema.post('save', function(doc, next) {
  console.log(`[${new Date().toISOString()}] User saved: ${doc.email}`);

  // Could also send welcome email, track analytics, etc.
  // sendWelcomeEmail(doc.email);

  next();
});

// Post-find: Log query duration
userSchema.post(/^find/, function(docs, next) {
  const duration = Date.now() - this.startTime;
  console.log(`Query took ${duration}ms, returned ${docs.length} documents`);
  next();
});

// Post-save error handling
userSchema.post('save', function(error, doc, next) {
  if (error.name === 'MongoServerError' && error.code === 11000) {
    // Handle duplicate key error
    const field = Object.keys(error.keyValue)[0];
    next(new Error(`${field} already exists`));
  } else {
    next(error);
  }
});

// Post-remove: Log deletion
userSchema.post('remove', function(doc) {
  console.log(`User ${doc.email} and all related data deleted`);
});
```

