**Complete Practical Example:**

```javascript
const userSchema = new mongoose.Schema({
  email: { type: String, unique: true },
  password: { type: String, select: false },
  loginAttempts: { type: Number, default: 0 },
  lastLogin: Date,
  isActive: { type: Boolean, default: true }
});

// PRE-SAVE: Hash password
userSchema.pre('save', async function(next) {
  if (!this.isModified('password')) return next();
  this.password = await bcrypt.hash(this.password, 12);
  next();
});

// PRE-FIND: Exclude inactive, add query timing
userSchema.pre(/^find/, function(next) {
  this.find({ isActive: true });
  this._startTime = Date.now();
  next();
});

// POST-FIND: Log query performance
userSchema.post(/^find/, function(docs, next) {
  console.log(`Query executed in ${Date.now() - this._startTime}ms`);
  next();
});

// POST-SAVE: Track new registrations
userSchema.post('save', function(doc, next) {
  if (doc.wasNew) {
    console.log(`New user registered: ${doc.email}`);
    // analyticsService.track('user_registered', { email: doc.email });
  }
  next();
});
```

**Key Points:**
- Use `next()` to pass control to the next middleware
- `this` refers to the document in document middleware
- `this` refers to the query in query middleware
- Pre hooks can modify data before it's saved
- Post hooks are great for logging, analytics, and cleanup
- Error handling post hooks receive error as first parameter
